// CorpFlowAI heartbeat evaluation (read-only). Thresholds mirror the runbook.
// Inputs: three HTTP nodes (comments, PRs, issues). Output: alert objects (may be empty).
const now = Date.now();
const H = 3600 * 1000;
const comments = $('GitHub: #493 comments').all().map(i => i.json).flat();
const prs = $('GitHub: open PRs').all().map(i => i.json).flat();

const alerts = [];

// 1) Dispatcher-digest freshness on #493 (> 12h => error)
const digest = comments.find(c => c && typeof c.body === 'string' && c.body.includes('Dispatcher Digest'));
const lastDigestMs = digest ? new Date(digest.created_at).getTime() : 0;
if (!digest || (now - lastDigestMs) > 12 * H) {
  const staleH = digest ? Math.round((now - lastDigestMs) / H) : null;
  alerts.push({ kind: 'digest_stale', target: '#493', severity: 'error', stale: staleH ? staleH + 'h' : 'none found', why: 'no dispatcher digest within the 12h active-day window', next: 'Cursor posts a dispatcher digest', anton: false });
}

// 2) Open-PR WIP cap (> 2 => error)
if (Array.isArray(prs) && prs.length > 2) {
  alerts.push({ kind: 'wip_cap', target: 'open PRs', severity: 'error', stale: 'n/a', why: prs.length + ' open PRs exceeds WIP cap of 2', next: 'merge or close PRs to drain WIP', anton: true });
}

// 3) Oldest open PR with unsurfaced CI (> 6h open => warn/error)
if (Array.isArray(prs)) {
  for (const pr of prs) {
    const ageH = (now - new Date(pr.created_at).getTime()) / H;
    if (ageH > 6) {
      alerts.push({ kind: 'pr_ci_unsurfaced', target: 'PR #' + pr.number, severity: ageH > 12 ? 'error' : 'warning', stale: Math.round(ageH) + 'h', why: 'PR open > 6h; confirm CI/build result is surfaced', next: 'surface CI result in a dispatcher digest', anton: false });
    }
  }
}

// Severity ladder: only error/fatal page. Warnings are logged, not paged.
const paging = alerts.filter(a => a.severity === 'error' || a.severity === 'fatal');
return [{ json: { checked: ['#493 comments', 'open PRs', 'open Action-Plan issues'], alert_count: paging.length, alerts: paging, all_signals: alerts, evaluated_at_utc: new Date(now).toISOString() } }];

